# Step 2: Load JSON file
with open("products.json", "r") as f:
    data = json.load(f)

# Step 3: Filter products
filtered = [x for x in data if x["price"] >= 116.38]

# Step 4: Sort
sorted_data = sorted(
    filtered,
    key=lambda x: (
        x["category"],
        -x["price"],
        x["name"]
    )
)

# Step 5: Print minified JSON
print(json.dumps(sorted_data, separators=(',', ':')))